837→function isOverlayObject(obj) {
838→  let current = obj;
839→  while (current) {
840→    if (current.name === 'DrawingPlaneOverlay' || current.name === 'ExtrusionPreview' ||
841→        current.name === 'PlaneGrid' || current.name === 'DrawPreview' ||
842→        current.name === 'SnapOverlay' || current.name === 'AlignmentGuides') {
843→      return true;
844→    }
845→    current = current.parent;
846→  }
847→  return false;
848→}
