  1→import { createPanel, createLeg, createFrame } from '../../domain/partModels';
  2→import { createAssembly } from '../../domain/assemblyModels';
  3→import { createConstraint } from '../../domain/constraintModels';
  4→import { computeFaceAlignedPartOverrides, buildFaceAttachmentConstraints } from '../../domain/facePlacement';
  5→import { snapToGrid, smartSnap3d } from '../snap';
  6→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  7→import { projectToPlane, planeLocalToWorld, faceToDrawingPlane, identifyFace, GROUND_PLANE } from '../../domain/drawingPlane';
  8→
  9→const partFactories = {
 10→  panel: createPanel,
 11→  leg: createLeg,
 12→  frame: createFrame,
 13→};
 14→
 15→function toDomainPoint(point) {
 16→  if (!point) return null;
 17→  return { x: point.x, y: point.z, z: point.y };
 18→}
 19→
 20→function capitalize(value) {
 21→  if (!value) return 'Module';
 22→  return value.charAt(0).toUpperCase() + value.slice(1);
 23→}
 24→
 25→function buildModuleName(project, objectId, partType) {
 26→  const label = capitalize(partType);
 27→  const count = (project.assemblies || []).filter((assembly) => assembly.objectId === objectId).length;
 28→  return `${label} ${count + 1}`;
 29→}
 30→
 31→function getPlacementObjectId(project, { hostPart, activeAssemblyId, selectedId, selectedType }) {
 32→  if (hostPart?.objectId) return hostPart.objectId;
 33→
 34→  if (activeAssemblyId) {
 35→    const activeAssembly = project.assemblies.find((assembly) => assembly.id === activeAssemblyId);
 36→    if (activeAssembly?.objectId) return activeAssembly.objectId;
 37→  }
 38→
 39→  if (selectedType === 'object') return selectedId;
 40→  if (selectedType === 'assembly') {
 41→    return project.assemblies.find((assembly) => assembly.id === selectedId)?.objectId || null;
 42→  }
 43→  if (selectedType === 'part') {
 44→    return project.parts.find((part) => part.id === selectedId)?.objectId || null;
 45→  }
 46→
 47→  return null;
 48→}
 49→
 50→function resolvePlacementTarget({
 51→  dispatch,
 52→  project,
 53→  partType,
 54→  hostPart,
 55→  activeAssemblyId,
 56→  selectedId,
 57→  selectedType,
 58→  placementModuleMode,
 59→}) {
 60→  const placementObjectId = getPlacementObjectId(project, {
 61→    hostPart,
 62→    activeAssemblyId,
 63→    selectedId,
 64→    selectedType,
 65→  });
 66→
 67→  const activeAssembly = activeAssemblyId
 68→    ? project.assemblies.find((assembly) => assembly.id === activeAssemblyId)
 69→    : null;
 70→  const canUseCurrentAssembly = (
 71→    placementModuleMode === 'current'
 72→    && activeAssembly
 73→    && (!placementObjectId || activeAssembly.objectId === placementObjectId)
 74→  );
 75→
 76→  if (canUseCurrentAssembly) {
 77→    return {
 78→      assemblyId: activeAssembly.id,
 79→      objectId: activeAssembly.objectId || placementObjectId || null,
 80→    };
 81→  }
 82→
 83→  if (placementObjectId) {
 84→    const assembly = createAssembly(buildModuleName(project, placementObjectId, partType), {
 85→      objectId: placementObjectId,
 86→      category: partType,
 87→      description: `${capitalize(partType)} module`,
 88→      source: 'manual',
 89→    });
 90→    dispatch({ type: 'ASSEMBLY_ADD', assembly });
 91→    return { assemblyId: assembly.id, objectId: placementObjectId };
 92→  }
 93→
 94→  return {
 95→    assemblyId: null,
 96→    objectId: hostPart?.objectId || null,
 97→  };
 98→}
 99→
100→function getPlacementPlane(toolState, drawingPlane) {
101→  return toolState.placementPlane || drawingPlane || GROUND_PLANE;
102→}
103→
104→function getDefaultPlacementMode(toolState, activeAssemblyId) {
105→  return toolState.placementModuleMode || (activeAssemblyId ? 'current' : 'new');
106→}
107→
108→function clearHover(editorDispatch) {
109→  editorDispatch({
110→    type: 'UPDATE_TOOL_STATE',
111→    payload: {
112→      hoverPartId: null,
113→      hoverFaceId: null,
114→      snapResult: null,
115→    },
116→  });
117→}
