245→function commitExtrusion(dispatch, editorDispatch, sourcePart, faceId, distance) {
246→  const result = computeExtrusionFromFace(sourcePart, faceId, distance);
247→  if (!result) return;
248→
249→  const part = createPanel(result.partOverrides);
250→  dispatch({ type: 'PART_ADD', part });
251→
252→  if (result.constraint) {
253→    const constraint = createConstraint({
254→      ...result.constraint,
255→      sourcePartId: part.id,
256→    });
257→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
258→  }
259→
260→  editorDispatch({
261→    type: 'SET_STATUS_MESSAGE',
262→    message: `Extruded ${Math.round(Math.abs(distance))} mm from ${faceId} face`,
263→  });
264→
265→  editorDispatch({
266→    type: 'UPDATE_TOOL_STATE',
267→    payload: {
268→      extruding: false,
269→      sourcePart: null,
270→      faceId: null,
271→      startPoint: null,
272→      faceNormal: null,
273→      extrusionDistance: 0,
274→      numericInput: '',
275→      snapResult: null,
276→    },
277→  });
