280→// Simple dimension getter (avoids importing partGeometry for this single use)
281→function getSimpleDims(part) {
282→  switch (part.type) {
283→    case 'panel': return { width: part.width, depth: part.depth, height: part.thickness };
284→    case 'leg': return { width: part.width, depth: part.depth, height: part.height };
285→    case 'frame': {
286→      const w = part.axis === 'y' ? part.width : part.length;
287→      const d = part.axis === 'y' ? part.length : part.width;
288→      return { width: w, depth: d, height: part.height };
289→    }
290→    default: return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
291→  }
292→}
293→
294→function axisToDim(axis) {
295→  return axis === 'x' ? 'width' : axis === 'y' ? 'depth' : 'height';
296→}
