  1→import { createSolid } from '../../domain/partModels';
  2→import { projectToPlane, planeLocalToWorld, GROUND_PLANE } from '../../domain/drawingPlane';
  3→import { smartSnap3d, snapToGrid } from '../snap';
  4→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  5→
  6→const MIN_PROFILE_AREA = 100;
  7→const MIN_POINT_DISTANCE = 10;
  8→
  9→function getDefaultExtrusionDepth(plane) {
 10→  return Math.abs(plane.normal.z) > 0.9 ? 120 : 60;
 11→}
 12→
 13→function polygonArea(points) {
 14→  if (!points || points.length < 3) return 0;
 15→  let total = 0;
 16→  for (let index = 0; index < points.length; index += 1) {
 17→    const current = points[index];
 18→    const next = points[(index + 1) % points.length];
 19→    total += current.u * next.v - next.u * current.v;
 20→  }
 21→  return Math.abs(total) / 2;
 22→}
