 24→export function createDrawProfileHandler3d({
 25→  dispatch,
 26→  editorDispatch,
 27→  project,
 28→  activeAssemblyId,
 29→  partType,
 30→  snapEnabled,
 31→  drawingPlane,
 32→  inferenceCache,
 33→}) {
 34→  const plane = drawingPlane || GROUND_PLANE;
 35→
 36→  function snapLocal(local, viewport) {
 37→    if (!snapEnabled) return { local, snapResult: null };
 38→
 39→    const worldPoint = planeLocalToWorld(local.u, local.v, plane);
 40→    const inferencePoints = inferenceCache
 41→      ? inferenceCache.getPoints(project.parts)
 42→      : null;
 43→    const camera = viewport?.getCamera?.();
 44→    const domElement = viewport?.getDomElement?.();
 45→
 46→    const result = smartSnap3d(worldPoint, {
 47→      inferencePoints,
 48→      gridSize: SKETCH_GRID_MINOR,
 49→      plane,
 50→      camera,
 51→      domElement,
 52→    });
 53→
 54→    if (result.inference) {
 55→      return {
 56→        local: projectToPlane(result.point, plane),
 57→        snapResult: result,
 58→      };
 59→    }
 60→
 61→    return {
 62→      local: {
 63→        u: snapToGrid(local.u, SKETCH_GRID_MINOR),
 64→        v: snapToGrid(local.v, SKETCH_GRID_MINOR),
 65→      },
 66→      snapResult: result,
 67→    };
 68→  }
 69→
 70→  function clearToolState() {
 71→    editorDispatch({
 72→      type: 'UPDATE_TOOL_STATE',
 73→      payload: {
 74→        drawingProfile: false,
 75→        profilePoints: [],
 76→        currentLocal: null,
 77→        snapResult: null,
 78→      },
 79→    });
 80→  }
 81→
 82→  function commitProfile(toolState, candidatePoint = null) {
 83→    const points = [...(toolState.profilePoints || [])];
 84→    if (candidatePoint) {
 85→      const last = points[points.length - 1];
 86→      if (!last || Math.hypot(candidatePoint.u - last.u, candidatePoint.v - last.v) >= MIN_POINT_DISTANCE) {
 87→        points.push(candidatePoint);
 88→      }
 89→    }
 90→
 91→    if (points.length < 3 || polygonArea(points) < MIN_PROFILE_AREA) {
 92→      editorDispatch({
 93→        type: 'SET_STATUS_MESSAGE',
 94→        message: 'Add at least three distinct points to create a solid profile.',
 95→      });
 96→      clearToolState();
 97→      return;
 98→    }
 99→
100→    const sourcePart = plane.sourcePartId
101→      ? project.parts.find((entry) => entry.id === plane.sourcePartId)
102→      : null;
103→
104→    const part = createSolid({
105→      position: { ...plane.origin },
106→      plane,
107→      profilePoints: points,
108→      extrusionDepth: getDefaultExtrusionDepth(plane),
109→      assemblyId: activeAssemblyId || sourcePart?.assemblyId || null,
110→      objectId: sourcePart?.objectId || null,
111→    });
112→
113→    dispatch({ type: 'PART_ADD', part });
114→
115→    if (activeAssemblyId) {
116→      dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
117→    }
118→
119→    editorDispatch({
120→      type: 'SET_STATUS_MESSAGE',
121→      message: `Solid created with ${points.length} points. Adjust extrusion in Properties.`,
122→    });
123→    clearToolState();
124→  }
125→
126→  return {
127→    onPointerDown(intersection, e, toolState, viewport) {
128→      if (e.button !== 0) return;
129→
130→      const planePoint = intersection?.drawingPlanePoint;
131→      if (!planePoint) return;
132→
133→      const local = projectToPlane(planePoint, plane);
134→      const { local: snapped, snapResult } = snapLocal(local, viewport);
135→      const existingPoints = toolState.profilePoints || [];
136→
137→      if (!toolState.drawingProfile) {
138→        editorDispatch({
139→          type: 'UPDATE_TOOL_STATE',
140→          payload: {
141→            drawingProfile: true,
142→            profilePoints: [snapped],
143→            currentLocal: snapped,
144→            snapResult,
145→          },
146→        });
147→        return;
148→      }
149→
150→      if (existingPoints.length >= 3) {
151→        const first = existingPoints[0];
152→        if (Math.hypot(snapped.u - first.u, snapped.v - first.v) < MIN_POINT_DISTANCE * 2) {
153→          commitProfile(toolState);
154→          return;
155→        }
156→      }
157→
158→      const last = existingPoints[existingPoints.length - 1];
159→      if (last && Math.hypot(snapped.u - last.u, snapped.v - last.v) < MIN_POINT_DISTANCE) {
160→        return;
161→      }
162→
163→      editorDispatch({
164→        type: 'UPDATE_TOOL_STATE',
165→        payload: {
166→          drawingProfile: true,
167→          profilePoints: [...existingPoints, snapped],
168→          currentLocal: snapped,
169→          snapResult,
170→        },
171→      });
172→    },
173→
174→    onPointerMove(intersection, e, toolState, viewport) {
175→      const planePoint = intersection?.drawingPlanePoint;
176→      if (!planePoint) return;
177→
178→      const local = projectToPlane(planePoint, plane);
179→      const { local: snapped, snapResult } = snapLocal(local, viewport);
180→
181→      editorDispatch({
182→        type: 'UPDATE_TOOL_STATE',
183→        payload: {
184→          currentLocal: snapped,
185→          snapResult,
186→        },
187→      });
188→    },
189→
190→    onHover(intersection, e, toolState, viewport) {
191→      if (toolState.drawingProfile) return;
192→
193→      const planePoint = intersection?.drawingPlanePoint;
194→      if (!planePoint) {
195→        editorDispatch({
196→          type: 'UPDATE_TOOL_STATE',
197→          payload: { snapResult: null },
198→        });
199→        return;
200→      }
201→
202→      const local = projectToPlane(planePoint, plane);
203→      const { snapResult } = snapLocal(local, viewport);
204→      editorDispatch({
205→        type: 'UPDATE_TOOL_STATE',
206→        payload: { snapResult },
207→      });
208→    },
209→
210→    onDoubleClick(intersection, e, toolState, viewport) {
211→      if (!toolState.drawingProfile) return;
212→
213→      const planePoint = intersection?.drawingPlanePoint;
214→      if (!planePoint) {
215→        commitProfile(toolState);
216→        return;
217→      }
218→
219→      const local = projectToPlane(planePoint, plane);
220→      const { local: snapped } = snapLocal(local, viewport);
221→      commitProfile(toolState, snapped);
222→    },
223→
224→    onKeyDown(e, toolState) {
225→      if (e.key === 'Escape') {
226→        clearToolState();
227→        return;
228→      }
229→
230→      if (e.key === 'Backspace' && toolState.drawingProfile) {
231→        e.preventDefault();
232→        const nextPoints = [...(toolState.profilePoints || [])];
233→        nextPoints.pop();
234→        editorDispatch({
235→          type: 'UPDATE_TOOL_STATE',
236→          payload: {
237→            drawingProfile: nextPoints.length > 0,
238→            profilePoints: nextPoints,
239→          },
240→        });
241→        return;
242→      }
243→
244→      if (e.key === 'Enter' && toolState.drawingProfile) {
245→        e.preventDefault();
246→        commitProfile(toolState);
247→      }
248→    },
249→
250→    getCursor() {
251→      return 'crosshair';
252→    },
253→  };
254→}
