  4→function createPartBase(type, overrides = {}) {
  5→  return {
  6→    id: generateId('part'),
  7→    type,
  8→    name: overrides.name || type,
  9→    assemblyId: overrides.assemblyId || null,
 10→    objectId: overrides.objectId || null,
 11→    parentId: overrides.parentId || null,
 12→    role: overrides.role || null,
 13→    generatedRole: overrides.generatedRole || null,
 14→    source: overrides.source || 'manual',
 15→    locked: overrides.locked ?? false,
 16→    sortIndex: overrides.sortIndex ?? 0,
 17→    position: { x: 0, y: 0, z: 0, ...overrides.position },
 18→    rotation: { x: 0, y: 0, z: 0, ...overrides.rotation },
 19→    fill: overrides.fill ?? 'rgba(184, 134, 11, 0.06)',
 20→    stroke: overrides.stroke ?? '#1E2433',
 21→    strokeWidth: overrides.strokeWidth ?? 2,
 22→    ...overrides,
 23→  };
 24→}
