154→export function SketchEditorProvider({ children }) {
155→  const [state, dispatch] = useReducer(
156→    sketchEditorReducer,
157→    null,
158→    createInitialSketchEditorState
159→  );
160→
161→  return (
162→    <SketchEditorContext.Provider value={{ state, dispatch }}>
163→      {children}
164→    </SketchEditorContext.Provider>
165→  );
