168→export function useSketchEditor() {
169→  const ctx = useContext(SketchEditorContext);
170→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
171→  const { state } = ctx;
172→  const viewport = state.workspaceMode === 'sheet' ? state.sheetViewport : state.modelViewport;
173→  return { ...state, viewport, dispatch: ctx.dispatch };
174→}
