  1→import * as THREE from 'three';
  2→import { getPartFaceCorners } from '../domain/partGeometry';
  3→
  4→// Snap indicator colors
  5→const CORNER_COLOR = 0x00cc66;
  6→const MIDPOINT_COLOR = 0x00cccc;
  7→const FACE_CENTER_COLOR = 0x3388ff;
  8→const HOVER_FACE_COLOR = 0xdaa520; // gold
  9→
 10→// Alignment guide axis colors
 11→const AXIS_COLORS = { x: 0xff4444, y: 0x44cc44, z: 0x4488ff };
 12→const ALIGNMENT_GUIDE_LENGTH = 2000; // mm
 13→
 14→const SNAP_DOT_SIZE = 8; // pixels (screen space)
 15→const FACE_OFFSET = 0.5; // mm offset to avoid z-fighting
 16→
 17→/**
 18→ * Three.js overlay for snap indicators, face highlights, and alignment guides.
 19→ * Follows the createDrawingPlaneOverlay() factory pattern.
 20→ */
 21→export function createSnapOverlay() {
 22→  const group = new THREE.Group();
 23→  group.name = 'SnapOverlay';
 24→
 25→  // --- Snap dot indicator ---
 26→  let snapDot = null;
 27→  const snapDotMaterials = {
 28→    corner: createDotMaterial(CORNER_COLOR),
 29→    midpoint: createDotMaterial(MIDPOINT_COLOR),
 30→    faceCenter: createDotMaterial(FACE_CENTER_COLOR),
 31→  };
 32→
 33→  // --- Face hover highlight ---
 34→  let faceHighlight = null;
 35→  const faceHighlightMaterial = new THREE.LineBasicMaterial({
 36→    color: HOVER_FACE_COLOR,
 37→    linewidth: 2,
 38→    depthTest: false,
 39→    transparent: true,
 40→    opacity: 0.9,
 41→  });
 42→
 43→  // --- Alignment guide lines ---
 44→  let alignmentLines = null;
 45→  const alignmentMaterials = {
 46→    x: new THREE.LineDashedMaterial({ color: AXIS_COLORS.x, dashSize: 10, gapSize: 6, transparent: true, opacity: 0.5, depthTest: false }),
 47→    y: new THREE.LineDashedMaterial({ color: AXIS_COLORS.y, dashSize: 10, gapSize: 6, transparent: true, opacity: 0.5, depthTest: false }),
 48→    z: new THREE.LineDashedMaterial({ color: AXIS_COLORS.z, dashSize: 10, gapSize: 6, transparent: true, opacity: 0.5, depthTest: false }),
 49→  };
 50→
 51→  function clearSnapDot() {
 52→    if (snapDot) {
 53→      group.remove(snapDot);
 54→      snapDot.geometry?.dispose();
 55→      snapDot = null;
 56→    }
 57→  }
 58→
 59→  function clearFaceHighlight() {
 60→    if (faceHighlight) {
 61→      group.remove(faceHighlight);
 62→      faceHighlight.geometry?.dispose();
 63→      faceHighlight = null;
 64→    }
 65→  }
 66→
 67→  function clearAlignmentLines() {
 68→    if (alignmentLines) {
 69→      group.remove(alignmentLines);
 70→      alignmentLines.traverse((child) => {
 71→        if (child.geometry) child.geometry.dispose();
 72→      });
 73→      alignmentLines = null;
 74→    }
 75→  }
 76→
 77→  return {
 78→    group,
 79→
 80→    /**
 81→     * Show/update a snap point indicator.
 82→     * @param {import('../editor/inferenceEngine').SnapResult|null} snapResult
 83→     */
 84→    updateSnapIndicator(snapResult) {
 85→      clearSnapDot();
 86→
 87→      if (!snapResult || !snapResult.inference) return;
 88→
 89→      const { inference } = snapResult;
 90→      const material = snapDotMaterials[inference.type] || snapDotMaterials.corner;
 91→
 92→      // Create a small sphere at the snap point (domain -> Three.js coords)
 93→      const geometry = new THREE.SphereGeometry(4, 8, 8);
 94→      snapDot = new THREE.Mesh(geometry, material);
 95→      // Domain to Three.js: x=x, y=z, z=y
 96→      snapDot.position.set(inference.x, inference.z, inference.y);
 97→      snapDot.renderOrder = 999;
 98→      group.add(snapDot);
 99→    },
100→
101→    /**
102→     * Show/update a face hover highlight (golden edge outline).
103→     * @param {Object|null} part - Part whose face to highlight
104→     * @param {string|null} faceId - Face ID ('+x', '-x', etc.)
105→     */
106→    updateHoverFace(part, faceId) {
107→      clearFaceHighlight();
108→
109→      if (!part || !faceId) return;
110→
111→      const corners = getPartFaceCorners(part, faceId);
112→      if (corners.length < 4) return;
113→
114→      // Get face normal direction for offset
115→      const normalDir = getFaceNormalDir(faceId);
116→
117→      // Convert corners domain -> Three.js with small normal offset
118→      const threeCorners = corners.map((c) => new THREE.Vector3(
119→        c.x + normalDir.x * FACE_OFFSET,
120→        c.z + normalDir.z * FACE_OFFSET, // domain z -> three y
121→        c.y + normalDir.y * FACE_OFFSET  // domain y -> three z
122→      ));
123→      threeCorners.push(threeCorners[0]); // close the loop
124→
125→      const geometry = new THREE.BufferGeometry().setFromPoints(threeCorners);
126→      faceHighlight = new THREE.LineLoop(geometry, faceHighlightMaterial);
127→      faceHighlight.renderOrder = 998;
128→      group.add(faceHighlight);
129→    },
130→
131→    /**
132→     * Show/update alignment guide lines.
133→     * @param {Array<{axis: 'x'|'y'|'z', value: number, points: Array}>} alignments
134→     */
135→    updateAlignmentLines(alignments) {
136→      clearAlignmentLines();
137→
138→      if (!alignments || alignments.length === 0) return;
139→
140→      const lineGroup = new THREE.Group();
141→      lineGroup.name = 'AlignmentGuides';
142→
143→      for (const align of alignments) {
144→        const material = alignmentMaterials[align.axis];
145→        if (!material) continue;
146→
147→        // Find bounding range of aligned points + cursor
148→        for (const p of align.points) {
149→          const start = new THREE.Vector3();
150→          const end = new THREE.Vector3();
151→
152→          // Create a line segment along the alignment axis through the point
153→          // Domain -> Three.js: x=x, y=z, z=y
154→          if (align.axis === 'x') {
155→            start.set(p.x, p.z, p.y - ALIGNMENT_GUIDE_LENGTH / 2);
156→            end.set(p.x, p.z, p.y + ALIGNMENT_GUIDE_LENGTH / 2);
157→          } else if (align.axis === 'y') {
158→            start.set(p.x, p.z - ALIGNMENT_GUIDE_LENGTH / 2, p.y);
159→            end.set(p.x, p.z + ALIGNMENT_GUIDE_LENGTH / 2, p.y);
160→          } else { // z
161→            start.set(p.x, p.z, p.y);
162→            // Only draw one guide per axis/value combo, not per point
163→            break;
164→          }
165→
166→          const geom = new THREE.BufferGeometry().setFromPoints([start, end]);
167→          const line = new THREE.LineSegments(geom, material);
168→          line.computeLineDistances();
169→          line.renderOrder = 997;
170→          lineGroup.add(line);
171→          break; // one guide line per axis is enough
172→        }
173→      }
174→
175→      alignmentLines = lineGroup;
176→      group.add(alignmentLines);
177→    },
178→
179→    /**
180→     * Clear all snap visuals.
181→     */
182→    clear() {
183→      clearSnapDot();
184→      clearFaceHighlight();
185→      clearAlignmentLines();
186→    },
187→
188→    /**
189→     * Dispose of all materials and geometry.
190→     */
191→    dispose() {
192→      clearSnapDot();
193→      clearFaceHighlight();
194→      clearAlignmentLines();
195→      Object.values(snapDotMaterials).forEach((m) => m.dispose());
196→      faceHighlightMaterial.dispose();
197→      Object.values(alignmentMaterials).forEach((m) => m.dispose());
198→    },
199→  };
200→}
201→
202→// --- Helpers ---
203→
204→function createDotMaterial(color) {
205→  return new THREE.MeshBasicMaterial({
206→    color,
207→    transparent: true,
208→    opacity: 0.9,
209→    depthTest: false,
210→  });
211→}
212→
213→function getFaceNormalDir(faceId) {
214→  switch (faceId) {
215→    case '+x': return { x: 1, y: 0, z: 0 };
216→    case '-x': return { x: -1, y: 0, z: 0 };
217→    case '+y': return { x: 0, y: 1, z: 0 };
218→    case '-y': return { x: 0, y: -1, z: 0 };
219→    case '+z': return { x: 0, y: 0, z: 1 };
220→    case '-z': return { x: 0, y: 0, z: -1 };
221→    default: return { x: 0, y: 0, z: 0 };
222→  }
223→}
