  27→function applyUpdate(state, nextProject, recordHistory = true) {
  28→  const normalizedProject = syncManualObjectDimensions(normalizeSketchObjects(nextProject));
  29→  const nextSnapshot = snapshotSketch(normalizedProject);
  30→  const history = recordHistory
  31→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  32→    : state.history;
  33→
  34→  return {
  35→    ...state,
  36→    history,
  37→    future: recordHistory ? [] : state.future,
  38→    project: normalizedProject,
  39→    isDirty: nextSnapshot !== state.savedSnapshot,
  40→  };
  41→}
  42→
  43→function mergePart(existing, updates) {
  44→  const merged = { ...existing, ...updates };
  45→  if (updates.position) {
  46→    merged.position = { ...existing.position, ...updates.position };
  47→  }
  48→  if (updates.rotation) {
  49→    merged.rotation = { ...existing.rotation, ...updates.rotation };
  50→  }
  51→  return merged;
  52→}
  53→
  54→function sanitizePart(part) {
  55→  if (part.type === 'dimension') return part;
  56→  return sanitizePartPosition(sanitizePartDimensions(part));
  57→}
  58→
  59→function applyConstraints(project) {
  60→  const constraints = project.constraints || [];
  61→  if (constraints.length === 0) return project;
  62→
  63→  const resolved = resolveConstraints(constraints, project.parts);
  64→  if (resolved.size === 0) return project;
  65→
  66→  return {
  67→    ...project,
  68→    parts: project.parts.map((part) => {
  69→      const newPos = resolved.get(part.id);
  70→      return newPos ? { ...part, position: newPos } : part;
  71→    }),
  72→  };
  73→}
  74→
  75→function updateBoundDimensions(project, updatedPartId) {
  76→  const updatedPart = project.parts.find((part) => part.id === updatedPartId);
  77→  if (!updatedPart) return project;
  78→
  79→  let changed = false;
  80→  const newParts = project.parts.map((part) => {
  81→    if (part.type === 'dimension' && part.boundPartId === updatedPartId) {
  82→      changed = true;
  83→      return updateBoundDimensionEndpoints(part, updatedPart);
  84→    }
  85→    return part;
  86→  });
  87→
  88→  return changed ? { ...project, parts: newParts } : project;
  89→}
  90→
  91→function clonePart(part, idMap) {
  92→  const newId = generateId('part');
  93→  idMap.set(part.id, newId);
  94→  return {
  95→    ...part,
  96→    id: newId,
  97→    name: `${part.name} (copy)`,
  98→    objectId: part.objectId || null,
  99→    source: 'manual',
 100→    locked: false,
 101→    position: {
 102→      ...part.position,
 103→      x: part.position.x + 50,
 104→      y: part.position.y + 50,
 105→    },
 106→  };
 107→}
 108→
 109→function getManagedObject(project, objectId) {
 110→  if (!objectId) return null;
 111→  return (project.objects || []).find((object) => object.id === objectId) || null;
 112→}
 113→
 114→function getManagedObjectForPart(project, partId) {
 115→  const part = project.parts.find((entry) => entry.id === partId);
 116→  const object = part?.objectId ? getManagedObject(project, part.objectId) : null;
 117→  return object?.editingPolicy === 'parametric' ? object : null;
 118→}
 119→
 120→function getManagedObjectForAssembly(project, assemblyId) {
 121→  const assembly = project.assemblies.find((entry) => entry.id === assemblyId);
 122→  const object = assembly?.objectId ? getManagedObject(project, assembly.objectId) : null;
 123→  return object?.editingPolicy === 'parametric' ? object : null;
 124→}
 125→
 126→function filterConstraintsForRemovedParts(constraints, idsToRemove) {
 127→  return constraints
 128→    .map((constraint) => {
 129→      // For equal_spacing, remove deleted parts from the partIds list
 130→      if (constraint.type === 'equal_spacing') {
 131→        const filtered = (constraint.partIds || []).filter((id) => !idsToRemove.has(id));
 132→        // Also clear referencePartId if it was removed
 133→        const refCleared = idsToRemove.has(constraint.referencePartId)
 134→          ? null
 135→          : constraint.referencePartId;
 136→        if (filtered.length < 2) return null; // not enough parts left
 137→        return { ...constraint, partIds: filtered, referencePartId: refCleared };
 138→      }
 139→      // Standard constraints: remove if either source or target is deleted
 140→      if (idsToRemove.has(constraint.sourcePartId) || idsToRemove.has(constraint.targetPartId)) {
 141→        return null;
 142→      }
 143→      return constraint;
 144→    })
 145→    .filter(Boolean);
 146→}
 147→
 148→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
 149→  const idsToRemove = new Set(partIds);
 150→  const assemblyIdSet = new Set(assemblyIds);
 151→
 152→  const childIds = new Set(
 153→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
 154→  );
 155→  for (const childId of childIds) idsToRemove.add(childId);
 156→
 157→  const constraints = filterConstraintsForRemovedParts(
 158→    project.constraints || [],
 159→    idsToRemove
 160→  );
 161→
 162→  return {
 163→    ...project,
 164→    parts: project.parts
 165→      .filter((part) => !idsToRemove.has(part.id))
 166→      .map((part) => {
 167→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 168→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 169→        }
 170→        return part;
 171→      }),
 172→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
 173→    constraints,
 174→  };
 175→}
 176→
 177→function removeObjectArtifacts(project, objectId) {
 178→  const partIds = project.parts
 179→    .filter((part) => part.objectId === objectId)
 180→    .map((part) => part.id);
 181→  const assemblyIds = project.assemblies
 182→    .filter((assembly) => assembly.objectId === objectId)
 183→    .map((assembly) => assembly.id);
 184→
 185→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
 186→}
 187→
 188→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
 189→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
 190→
 191→  return (sheets || []).map((sheet) => ({
 192→    ...sheet,
 193→    viewports: (sheet.viewports || []).map((viewport) => {
 194→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
 195→        return viewport;
 196→      }
 197→
 198→      if (viewport.sourceView === 'sketch_assembly_top') {
 199→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
 200→      }
 201→      if (viewport.sourceView === 'sketch_assembly_front') {
 202→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
 203→      }
 204→      if (viewport.sourceView === 'sketch_assembly_side') {
 205→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
 206→      }
 207→      if (viewport.sourceView === 'sketch_part_list') {
 208→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
 209→      }
 210→
 211→      return viewport;
 212→    }),
 213→  }));
 214→}
 215→
 216→function detachManagedObject(project, objectId) {
 217→  return {
 218→    ...project,
 219→    objects: (project.objects || []).map((object) => (
 220→      object.id === objectId
 221→        ? {
 222→            ...object,
 223→            source: 'custom',
 224→            editingPolicy: 'manual',
 225→            templateType: null,
 226→            templateParams: null,
 227→            summary: object.summary || 'Detached custom object',
 228→            updatedAt: new Date().toISOString(),
 229→          }
 230→        : object
 231→    )),
 232→    assemblies: project.assemblies.map((assembly) => (
 233→      assembly.objectId === objectId
 234→        ? {
 235→            ...assembly,
 236→            source: 'manual',
 237→            role: assembly.role || null,
 238→          }
 239→        : assembly
 240→    )),
 241→    parts: project.parts.map((part) => (
 242→      part.objectId === objectId
 243→        ? {
 244→          ...part,
 245→            source: 'manual',
 246→            locked: false,
 247→          }
 248→        : part
 249→    )),
 250→  };
 251→}
 252→
 253→function addGeneratedObject(project, generated) {
 254→  return {
 255→    ...project,
 256→    objects: [...(project.objects || []), generated.object],
 257→    assemblies: [...project.assemblies, ...generated.assemblies],
 258→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
 259→  };
 260→}
 261→
 262→function collectConstraintsForObject(project, objectId) {
 263→  const objectPartIds = new Set(
 264→    project.parts.filter((part) => part.objectId === objectId).map((part) => part.id)
 265→  );
 266→  return (project.constraints || []).filter((constraint) => {
 267→    if (constraint.type === 'equal_spacing') {
 268→      return (constraint.partIds || []).some((id) => objectPartIds.has(id));
 269→    }
 270→    return objectPartIds.has(constraint.sourcePartId) || objectPartIds.has(constraint.targetPartId);
 271→  });
 272→}
 273→
 274→function buildRoleMap(parts, objectId) {
 275→  const map = new Map();
 276→  for (const part of parts) {
 277→    if (part.objectId === objectId && part.generatedRole) {
 278→      map.set(part.id, part.generatedRole);
 279→    }
 280→  }
 281→  return map;
 282→}
 283→
 284→function buildReverseRoleMap(parts, objectId) {
 285→  const map = new Map();
 286→  for (const part of parts) {
 287→    if (part.objectId === objectId && part.generatedRole) {
 288→      map.set(part.generatedRole, part.id);
 289→    }
 290→  }
 291→  return map;
 292→}
 293→
 294→function remapConstraints(constraints, oldRoleMap, newRoleMap) {
 295→  return constraints
 296→    .map((constraint) => {
 297→      if (constraint.type === 'equal_spacing') {
 298→        const newPartIds = (constraint.partIds || []).map((id) => {
 299→          const role = oldRoleMap.get(id);
 300→          return role ? (newRoleMap.get(role) || null) : id;
 301→        }).filter(Boolean);
 302→
 303→        let newRefId = constraint.referencePartId;
 304→        if (newRefId) {
 305→          const refRole = oldRoleMap.get(newRefId);
 306→          newRefId = refRole ? (newRoleMap.get(refRole) || null) : newRefId;
 307→        }
 308→
 309→        if (newPartIds.length < 2) return null;
 310→        return { ...constraint, partIds: newPartIds, referencePartId: newRefId };
 311→      }
 312→
 313→      let newSourceId = constraint.sourcePartId;
 314→      let newTargetId = constraint.targetPartId;
 315→
 316→      const sourceRole = oldRoleMap.get(newSourceId);
 317→      if (sourceRole) newSourceId = newRoleMap.get(sourceRole) || null;
 318→
 319→      const targetRole = oldRoleMap.get(newTargetId);
 320→      if (targetRole) newTargetId = newRoleMap.get(targetRole) || null;
 321→
 322→      if (!newSourceId || !newTargetId) return null;
 323→      return { ...constraint, sourcePartId: newSourceId, targetPartId: newTargetId };
 324→    })
 325→    .filter(Boolean);
 326→}
 327→
 328→function rebuildManagedObject(project, object, params) {
 329→  const oldAssemblyIds = project.assemblies
 330→    .filter((assembly) => assembly.objectId === object.id)
 331→    .map((assembly) => assembly.id);
 332→
 333→  // Collect constraints referencing old parts and build role map before stripping
 334→  const affectedConstraints = collectConstraintsForObject(project, object.id);
 335→  const oldRoleMap = buildRoleMap(project.parts, object.id);
 336→
 337→  const strippedProject = removeObjectArtifacts(project, object.id);
 338→  const generated = generateObjectFromTemplate(object.templateType, params, {
 339→    objectId: object.id,
 340→    name: object.name,
 341→    origin: object.origin,
 342→  });
 343→
 344→  const nextProject = addGeneratedObject({
 345→    ...strippedProject,
 346→    objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
 347→    sheets: retargetManagedViewports(strippedProject.sheets, object.id, oldAssemblyIds),
 348→  }, generated);
 349→
 350→  // Remap constraints to new part IDs via role matching
 351→  if (affectedConstraints.length > 0) {
 352→    const newRoleMap = buildReverseRoleMap(nextProject.parts, object.id);
 353→    const remapped = remapConstraints(affectedConstraints, oldRoleMap, newRoleMap);
 354→    // Merge: keep constraints not affected + add remapped ones
 355→    const affectedIds = new Set(affectedConstraints.map((c) => c.id));
 356→    const kept = (nextProject.constraints || []).filter((c) => !affectedIds.has(c.id));
 357→    return { ...nextProject, constraints: [...kept, ...remapped] };
 358→  }
 359→
 360→  return nextProject;
 361→}
