 363→function sketchReducer(state, action) {
 364→  switch (action.type) {
 365→    case 'SKETCH_NEW': {
 366→      const newProject = syncManualObjectDimensions(
 367→        normalizeSketchObjects(action.project || createSketchProject())
 368→      );
 369→      return {
 370→        project: newProject,
 371→        isDirty: false,
 372→        savedSnapshot: snapshotSketch(newProject),
 373→        history: [],
 374→        future: [],
 375→      };
 376→    }
 377→
 378→    case 'SKETCH_LOAD': {
 379→      const loaded = syncManualObjectDimensions(normalizeSketchObjects(action.project));
 380→      return {
 381→        project: loaded,
 382→        isDirty: false,
 383→        savedSnapshot: snapshotSketch(loaded),
 384→        history: [],
 385→        future: [],
 386→      };
 387→    }
 388→
 389→    case 'PART_ADD': {
 390→      const part = sanitizePart(action.part);
 391→      const assembly = part.assemblyId
 392→        ? state.project.assemblies.find((entry) => entry.id === part.assemblyId)
 393→        : null;
 394→      const nextPart = assembly && assembly.objectId
 395→        ? { ...part, objectId: assembly.objectId }
 396→        : part;
 397→      let nextProject = {
 398→        ...state.project,
 399→        updatedAt: new Date().toISOString(),
 400→        parts: [...state.project.parts, nextPart],
 401→      };
 402→      nextProject = applyConstraints(nextProject);
 403→      return applyUpdate(state, nextProject);
 404→    }
 405→
 406→    case 'PART_UPDATE': {
 407→      const managedObject = getManagedObjectForPart(state.project, action.part.id);
 408→      if (managedObject && !action.allowManagedUpdate) return state;
 409→
 410→      let nextProject = {
 411→        ...state.project,
 412→        updatedAt: new Date().toISOString(),
 413→        parts: state.project.parts.map((part) => {
 414→          if (part.id !== action.part.id) return part;
 415→          const merged = mergePart(part, action.part);
 416→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
 417→        }),
 418→      };
 419→      nextProject = applyConstraints(nextProject);
 420→      nextProject = updateBoundDimensions(nextProject, action.part.id);
 421→      return applyUpdate(state, nextProject);
 422→    }
 423→
 424→    case 'PART_DELETE': {
 425→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 426→      if (managedObject) return state;
 427→
 428→      const partId = action.partId;
 429→      const childIds = new Set(
 430→        state.project.parts.filter((part) => part.parentId === partId).map((part) => part.id)
 431→      );
 432→      const idsToRemove = new Set([partId, ...childIds]);
 433→
 434→      const constraints = filterConstraintsForRemovedParts(
 435→        state.project.constraints || [],
 436→        idsToRemove
 437→      );
 438→
 439→      return applyUpdate(state, {
 440→        ...state.project,
 441→        updatedAt: new Date().toISOString(),
 442→        parts: state.project.parts
 443→          .filter((part) => !idsToRemove.has(part.id))
 444→          .map((part) => {
 445→            if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 446→              return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 447→            }
 448→            return part;
 449→          }),
 450→        assemblies: state.project.assemblies.map((assembly) => ({
 451→          ...assembly,
 452→          partIds: assembly.partIds.filter((id) => !idsToRemove.has(id)),
 453→        })),
 454→        constraints,
 455→      });
 456→    }
 457→
 458→    case 'PART_CLONE': {
 459→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 460→      if (managedObject) return state;
 461→
 462→      const part = state.project.parts.find((entry) => entry.id === action.partId);
 463→      if (!part) return state;
 464→
 465→      const idMap = new Map();
 466→      const cloned = clonePart(part, idMap);
 467→      const children = state.project.parts.filter((entry) => entry.parentId === action.partId);
 468→      const clonedChildren = children.map((child) => {
 469→        const clonedChild = clonePart(child, idMap);
 470→        clonedChild.parentId = cloned.id;
 471→        return clonedChild;
 472→      });
 473→
 474→      const newParts = [cloned, ...clonedChildren];
 475→      let assemblies = state.project.assemblies;
 476→      if (part.assemblyId) {
 477→        assemblies = assemblies.map((assembly) => {
 478→          if (assembly.id === part.assemblyId) {
 479→            return {
 480→              ...assembly,
 481→              partIds: [...assembly.partIds, ...newParts.map((entry) => entry.id)],
 482→            };
 483→          }
 484→          return assembly;
 485→        });
 486→        for (const nextPart of newParts) {
 487→          nextPart.assemblyId = part.assemblyId;
 488→        }
 489→      }
 490→
 491→      return applyUpdate(state, {
 492→        ...state.project,
 493→        updatedAt: new Date().toISOString(),
 494→        parts: [...state.project.parts, ...newParts],
 495→        assemblies,
 496→      });
 497→    }
 498→
 499→    case 'ASSEMBLY_ADD':
 500→      return applyUpdate(state, {
 501→        ...state.project,
 502→        updatedAt: new Date().toISOString(),
 503→        assemblies: [...state.project.assemblies, { ...action.assembly, source: action.assembly.source || 'manual' }],
 504→      });
 505→
 506→    case 'ASSEMBLY_UPDATE': {
 507→      const managedObject = getManagedObjectForAssembly(state.project, action.assembly.id);
 508→      if (managedObject) return state;
 509→
 510→      return applyUpdate(state, {
 511→        ...state.project,
 512→        updatedAt: new Date().toISOString(),
 513→        assemblies: state.project.assemblies.map((assembly) => (
 514→          assembly.id === action.assembly.id ? { ...assembly, ...action.assembly } : assembly
 515→        )),
 516→      });
 517→    }
 518→
 519→    case 'ASSEMBLY_DELETE': {
 520→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 521→      if (managedObject) return state;
 522→
 523→      const assemblyId = action.assemblyId;
 524→      return applyUpdate(state, {
 525→        ...state.project,
 526→        updatedAt: new Date().toISOString(),
 527→        assemblies: state.project.assemblies.filter((assembly) => assembly.id !== assemblyId),
 528→        parts: state.project.parts.map((part) => (
 529→          part.assemblyId === assemblyId ? { ...part, assemblyId: null } : part
 530→        )),
 531→      });
 532→    }
 533→
 534→    case 'ASSEMBLY_MOVE': {
 535→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 536→      if (managedObject) {
 537→        return sketchReducer(state, {
 538→          type: 'OBJECT_MOVE',
 539→          objectId: managedObject.id,
 540→          delta: action.delta,
 541→        });
 542→      }
 543→
 544→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 545→      if (!assembly) return state;
 546→
 547→      const partIdSet = new Set(assembly.partIds);
 548→      let nextProject = {
 549→        ...state.project,
 550→        updatedAt: new Date().toISOString(),
 551→        parts: state.project.parts.map((part) => {
 552→          if (!partIdSet.has(part.id) || part.type === 'dimension') return part;
 553→          const moved = {
 554→            ...part,
 555→            position: {
 556→              x: part.position.x + (action.delta.dx || 0),
 557→              y: part.position.y + (action.delta.dy || 0),
 558→              z: part.position.z + (action.delta.dz || 0),
 559→            },
 560→          };
 561→          return sanitizePart(moved);
 562→        }),
 563→      };
 564→      nextProject = applyConstraints(nextProject);
 565→      for (const partId of partIdSet) {
 566→        nextProject = updateBoundDimensions(nextProject, partId);
 567→      }
 568→      return applyUpdate(state, nextProject);
 569→    }
 570→
 571→    case 'ASSEMBLY_DELETE_WITH_PARTS': {
 572→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 573→      if (managedObject) {
 574→        return sketchReducer(state, {
 575→          type: 'OBJECT_DELETE',
 576→          objectId: managedObject.id,
 577→        });
 578→      }
 579→
 580→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 581→      if (!assembly) return state;
 582→
 583→      return applyUpdate(state, {
 584→        ...removePartsAndAssemblies(state.project, {
 585→          partIds: assembly.partIds,
 586→          assemblyIds: [assembly.id],
 587→        }),
 588→        updatedAt: new Date().toISOString(),
 589→      });
 590→    }
 591→
 592→    case 'ASSEMBLY_ADD_PART': {
 593→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 594→      if (managedObject) return state;
 595→
 596→       const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 597→
 598→      return applyUpdate(state, {
 599→        ...state.project,
 600→        updatedAt: new Date().toISOString(),
 601→        assemblies: state.project.assemblies.map((assembly) => (
 602→          assembly.id === action.assemblyId && !assembly.partIds.includes(action.partId)
 603→            ? { ...assembly, partIds: [...assembly.partIds, action.partId] }
 604→            : assembly
 605→        )),
 606→        parts: state.project.parts.map((part) => (
 607→          part.id === action.partId
 608→            ? { ...part, assemblyId: action.assemblyId, objectId: assembly?.objectId || part.objectId || null }
 609→            : part
 610→        )),
 611→      });
 612→    }
 613→
 614→    case 'ASSEMBLY_REMOVE_PART': {
 615→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 616→      if (managedObject) return state;
 617→
 618→      return applyUpdate(state, {
 619→        ...state.project,
 620→        updatedAt: new Date().toISOString(),
 621→        assemblies: state.project.assemblies.map((assembly) => (
 622→          assembly.id === action.assemblyId
 623→            ? { ...assembly, partIds: assembly.partIds.filter((id) => id !== action.partId) }
 624→            : assembly
 625→        )),
 626→        parts: state.project.parts.map((part) => (
 627→          part.id === action.partId && part.assemblyId === action.assemblyId
 628→            ? { ...part, assemblyId: null }
 629→            : part
 630→        )),
 631→      });
 632→    }
 633→
 634→    case 'ASSEMBLY_CLONE': {
 635→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 636→      if (managedObject) return state;
 637→
 638→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 639→      if (!assembly) return state;
 640→
 641→      const idMap = new Map();
 642→      const newAssemblyId = generateId('asm');
 643→      const newAssembly = {
 644→        ...assembly,
 645→        id: newAssemblyId,
 646→        name: `${assembly.name} (copy)`,
 647→        partIds: [],
 648→        objectId: assembly.objectId || null,
 649→        source: 'manual',
 650→      };
 651→
 652→      const assemblyParts = state.project.parts.filter((part) => part.assemblyId === action.assemblyId);
 653→      const clonedParts = [];
 654→
 655→      for (const part of assemblyParts) {
 656→        const cloned = clonePart(part, idMap);
 657→        cloned.assemblyId = newAssemblyId;
 658→        clonedParts.push(cloned);
 659→      }
 660→
 661→      for (const clonedPart of clonedParts) {
 662→        if (clonedPart.parentId && idMap.has(clonedPart.parentId)) {
 663→          clonedPart.parentId = idMap.get(clonedPart.parentId);
 664→        }
 665→      }
 666→
 667→      newAssembly.partIds = clonedParts.map((part) => part.id);
 668→
 669→      return applyUpdate(state, {
 670→        ...state.project,
 671→        updatedAt: new Date().toISOString(),
 672→        parts: [...state.project.parts, ...clonedParts],
 673→        assemblies: [...state.project.assemblies, newAssembly],
 674→      });
 675→    }
 676→
 677→    case 'OBJECT_ADD':
 678→      return applyUpdate(state, {
 679→        ...state.project,
 680→        updatedAt: new Date().toISOString(),
 681→        objects: [...(state.project.objects || []), createSketchObject(action.object.name, action.object)],
 682→      });
 683→
 684→    case 'OBJECT_CREATE': {
 685→      const object = createSketchObject(action.object.name, action.object);
 686→      const assemblies = (action.assemblies || []).map((assembly) => createAssembly(assembly.name, assembly));
 687→      return applyUpdate(state, {
 688→        ...state.project,
 689→        updatedAt: new Date().toISOString(),
 690→        objects: [...(state.project.objects || []), object],
 691→        assemblies: [...state.project.assemblies, ...assemblies],
 692→      });
 693→    }
 694→
 695→    case 'OBJECT_UPDATE':
 696→      return applyUpdate(state, {
 697→        ...state.project,
 698→        updatedAt: new Date().toISOString(),
 699→        objects: (state.project.objects || []).map((object) => (
 700→          object.id === action.object.id
 701→            ? {
 702→                ...object,
 703→                ...action.object,
 704→                templateParams: action.object.templateParams
 705→                  ? { ...action.object.templateParams }
 706→                  : object.templateParams,
 707→                dimensions: action.object.dimensions
 708→                  ? { ...action.object.dimensions }
 709→                  : object.dimensions,
 710→                updatedAt: new Date().toISOString(),
 711→              }
 712→            : object
 713→        )),
 714→      });
 715→
 716→    case 'OBJECT_RESIZE': {
 717→      const object = getManagedObject(state.project, action.objectId);
 718→      if (!object || object.editingPolicy === 'parametric') return state;
 719→
 720→      const now = new Date().toISOString();
 721→      const objectParts = state.project.parts.filter((part) => part.objectId === object.id);
 722→      const geometryParts = objectParts.filter(isObjectGeometryPart);
 723→      const requestedDimensions = action.dimensions || {};
 724→
 725→      if (geometryParts.length === 0) {
 726→        const nextDimensions = {
 727→          ...object.dimensions,
 728→          ...(Number.isFinite(requestedDimensions.width) ? { width: clampDimension(requestedDimensions.width) } : {}),
 729→          ...(Number.isFinite(requestedDimensions.depth) ? { depth: clampDimension(requestedDimensions.depth) } : {}),
 730→          ...(Number.isFinite(requestedDimensions.height) ? { height: clampDimension(requestedDimensions.height) } : {}),
 731→        };
 732→
 733→        const unchanged = (
 734→          object.dimensions?.width === nextDimensions.width
 735→          && object.dimensions?.depth === nextDimensions.depth
 736→          && object.dimensions?.height === nextDimensions.height
 737→        );
 738→        if (unchanged) return state;
 739→
 740→        return applyUpdate(state, {
 741→          ...state.project,
 742→          updatedAt: now,
 743→          objects: (state.project.objects || []).map((entry) => (
 744→            entry.id === object.id
 745→              ? {
 746→                  ...entry,
 747→                  dimensions: nextDimensions,
 748→                  updatedAt: now,
 749→                }
 750→              : entry
 751→          )),
 752→        });
 753→      }
 754→
 755→      const currentBounds = getPartsBounds3d(geometryParts);
 756→      const { nextDimensions, scaleFactors } = buildObjectScaleFactors(currentBounds, requestedDimensions);
 757→      const hasScaleChange = hasMeaningfulScaleChange(scaleFactors);
 758→
 759→      if (!hasScaleChange) {
