 769→          entry.id === object.id
 770→            ? {
 771→                ...entry,
 772→                origin: scalePoint3d(entry.origin, anchor, scaleFactors),
 773→                dimensions: nextDimensions,
 774→                updatedAt: now,
 775→              }
 776→            : entry
