 801→      const strippedProject = removeObjectArtifacts(state.project, object.id);
 802→      return applyUpdate(state, {
 803→        ...strippedProject,
 804→        updatedAt: new Date().toISOString(),
 805→        objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
