1000→    }
1001→
1002→    case 'TEMPLATE_REGENERATE': {
1003→      const object = action.objectId
1004→        ? getManagedObject(state.project, action.objectId)
1005→        : getManagedObjectForAssembly(state.project, action.assemblyId);
1006→      if (!object || !object.templateType) return state;
1007→
1008→      const nextProject = rebuildManagedObject(state.project, object, action.params);
1009→      return applyUpdate(state, {
1010→        ...nextProject,
1011→        updatedAt: new Date().toISOString(),
1012→      });
1013→    }
1014→
1015→    case 'TEMPLATE_DETACH': {
1016→      const object = action.objectId
1017→        ? getManagedObject(state.project, action.objectId)
1018→        : getManagedObjectForAssembly(state.project, action.assemblyId);
1019→      if (!object) return state;
1020→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
1021→    }
1022→
1023→    case 'UNDO': {
1024→      if (state.history.length === 0) return state;
1025→      const previous = state.history[state.history.length - 1];
1026→      return {
1027→        ...state,
1028→        project: previous,
1029→        history: state.history.slice(0, -1),
1030→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
1031→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
1032→      };
1033→    }
1034→
1035→    case 'REDO': {
1036→      if (state.future.length === 0) return state;
1037→      const next = state.future[0];
1038→      return {
1039→        ...state,
1040→        project: next,
1041→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
1042→        future: state.future.slice(1),
1043→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
1044→      };
1045→    }
1046→
1047→    case 'MARK_SAVED':
1048→      return {
1049→        ...state,
1050→        isDirty: false,
1051→        savedSnapshot: snapshotSketch(state.project),
1052→      };
1053→
1054→    default:
1055→      return state;
1056→  }
1057→}
1058→
1059→function createInitialState(project) {
1060→  return {
1061→    project: syncManualObjectDimensions(normalizeSketchObjects(project)),
1062→    isDirty: false,
1063→    savedSnapshot: snapshotSketch(syncManualObjectDimensions(normalizeSketchObjects(project))),
1064→    history: [],
1065→    future: [],
1066→  };
1067→}
1068→
1069→export function SketchProvider({ children, initialProject }) {
1070→  const [state, dispatch] = useReducer(
1071→    sketchReducer,
1072→    syncManualObjectDimensions(normalizeSketchObjects(initialProject || createSketchProject())),
1073→    createInitialState
1074→  );
1075→
1076→  return (
1077→    <SketchContext.Provider value={{ state, dispatch }}>
1078→      {children}
1079→    </SketchContext.Provider>
1080→  );
1081→}
1082→
1083→export function useSketch() {
1084→  const ctx = useContext(SketchContext);
1085→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
1086→  const { state, dispatch } = ctx;
1087→
1088→  const getPart = useCallback(
1089→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
1090→    [state.project.parts]
1091→  );
1092→
1093→  const getAssembly = useCallback(
1094→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
1095→    [state.project.assemblies]
1096→  );
1097→
1098→  const getObject = useCallback(
1099→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
1100→    [state.project.objects]
1101→  );
1102→
1103→  const getPartsForAssembly = useCallback(
1104→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
1105→    [state.project.parts]
1106→  );
1107→
1108→  const getChildParts = useCallback(
1109→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
1110→    [state.project.parts]
1111→  );
1112→
1113→  const getAssembliesForObject = useCallback(
1114→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
1115→    [state.project.assemblies]
1116→  );
1117→
1118→  return {
1119→    project: state.project,
1120→    isDirty: state.isDirty,
1121→    canUndo: state.history.length > 0,
1122→    canRedo: state.future.length > 0,
1123→    dispatch,
1124→    getPart,
1125→    getAssembly,
1126→    getObject,
1127→    getPartsForAssembly,
1128→    getChildParts,
1129→    getAssembliesForObject,
1130→  };
1131→}
