158→function buildInsetConstraint(sourcePart, targetPart, axisConfig) {
159→  const sourceExt = getPartExtents(sourcePart);
160→  const targetExt = getPartExtents(targetPart);
161→  const axis = axisConfig.axis;
162→
163→  const sourceStart = sourcePart.position[axis];
164→  const sourceSize = getAxisSize(sourceExt, axis);
165→  const targetStart = targetPart.position[axis];
166→  const targetSize = getAxisSize(targetExt, axis);
167→
168→  const startOffset = sourceStart - targetStart;
169→  const endOffset = (targetStart + targetSize) - (sourceStart + sourceSize);
170→  const centerDelta = Math.abs(startOffset - endOffset);
171→
172→  if (centerDelta <= 4) {
173→    return {
174→      type: 'center_axis',
175→      axis,
176→      sourceAnchor: axisConfig.startAnchor,
177→      targetAnchor: axisConfig.startAnchor,
178→    };
179→  }
180→
181→  if (Math.abs(startOffset) <= Math.abs(endOffset)) {
182→    return {
183→      type: 'inset_edge',
184→      sourceAnchor: axisConfig.startAnchor,
185→      targetAnchor: axisConfig.startAnchor,
186→      offset: startOffset,
187→    };
188→  }
189→
190→  return {
191→    type: 'inset_edge',
192→    sourceAnchor: axisConfig.endAnchor,
193→    targetAnchor: axisConfig.endAnchor,
194→    offset: endOffset,
195→  };
196→}
