198→export function buildFaceAttachmentConstraints(sourcePart, targetPart, faceId) {
199→  const mapping = FACE_ANCHOR_MAP[faceId];
200→  if (!mapping) return [];
201→
202→  const constraints = [
203→    {
204→      type: 'attach_face',
205→      sourcePartId: sourcePart.id,
206→      targetPartId: targetPart.id,
207→      sourceAnchor: mapping.sourceAnchor,
208→      targetAnchor: mapping.targetAnchor,
209→      offset: 0,
210→    },
211→  ];
212→
213→  for (const axisConfig of mapping.planeAxes) {
214→    constraints.push({
215→      sourcePartId: sourcePart.id,
216→      targetPartId: targetPart.id,
217→      ...buildInsetConstraint(sourcePart, targetPart, axisConfig),
218→    });
219→  }
220→
221→  return constraints;
222→}
